param (
    [string]$TargetDir,
    [string]$ProjectName
)

# ?? Interactive Mode
if ([string]::IsNullOrEmpty($TargetDir)) {
    Write-Host "`n[?] Target Project Path?" -ForegroundColor Yellow -NoNewline
    Write-Host " (You can drag the folder here)" -ForegroundColor Gray
    $TargetDir = (Read-Host " >> ").Trim('"')
}

if ([string]::IsNullOrEmpty($ProjectName)) {
    Write-Host "[?] New Project Label?" -ForegroundColor Yellow -NoNewline
    Write-Host " (e.g., PCLMS)" -ForegroundColor Gray
    $ProjectName = Read-Host " >> "
}

# Basic Check
if (!(Test-Path $TargetDir)) {
    Write-Host "!! Error: Path not found '$TargetDir'" -ForegroundColor Red
    Pause
    exit
}

Write-Host "`n?? Injecting Standalone Tech Lead Skills..." -ForegroundColor Cyan

$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-SkillFile {
    param($Path, $Base64Content)
    $FullDir = [System.IO.Path]::GetDirectoryName($Path)
    if (!(Test-Path $FullDir)) {
        New-Item -ItemType Directory -Path $FullDir -Force | Out-Null
    }
    
    $Bytes = [Convert]::FromBase64String($Base64Content)
    $Content = [System.Text.Encoding]::UTF8.GetString($Bytes)
    
    $Content = $Content -replace "PTWCS", $ProjectName
    $Content = $Content -replace "PCLMS_BK_new", $ProjectName
    
    [System.IO.File]::WriteAllText($Path, $Content, $Utf8NoBom)
    Write-Host "  [OK] Saved: $([System.IO.Path]::GetFileName($Path))" -ForegroundColor Green
}

# Start Injection
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\architect-protocol\architect_protocol_guide.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\architect-protocol\module1_context_mapping.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\architect-protocol\module2_debt_detection.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\architect-protocol\module3_architectural_blueprinting.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\architect-protocol\module4_boy_scout_execution.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\architect-protocol\module5_verification.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\claude-reasoning-modes\SKILL.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\claude-reasoning-modes\claude_integration_guide.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir ".agent\skills\claude-reasoning-modes\claude_reasoning_modes.md") -Base64Content ""
Write-SkillFile -Path (Join-Path $TargetDir "user_rules.md") -Base64Content ""
Write-Host "
  >> All skills injected successfully! You are good to go." -ForegroundColor Yellow
Write-Host "  >> Target: $TargetDir"
Write-Host "  >> Project: $ProjectName"
Write-Host "
[Press any key to exit...]"
$null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")